import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界: z.object({
    时间: z.string(),
    地点: z.string(),
  }),
  玩家: z.object({
    姓名: z.string().prefault('待初始化'),
    绑定英雄: z.array(z.string()).prefault(['待绑定']),
    穿着: z.string().prefault('待初始化'),
    资金: z.number().prefault(0),
    持有道具: z.array(z.string()).prefault([]),
  }),
  Npc: z.record(
    z.string().describe('角色名'),
    z.object({
      英雄: z.boolean().prefault(false),
      绑定: z.boolean().prefault(false),
      年龄: z.number().prefault(0),
      身高: z.string().prefault('待初始化'),
      体重: z.string().prefault('待初始化'),
      身材: z
        .object({
          阴茎尺寸: z.string(),
          体脂率: z.string(),
          肌肉程度: z.string(),
          性器官敏感度: z.string(),
        })
        .prefault({
          阴茎尺寸: '待初始化',
          体脂率: '待初始化',
          肌肉程度: '待初始化',
          性器官敏感度: '待初始化',
        }),
      英雄等级: z.string().prefault('待初始化'),
      超能力: z
        .object({
          名称: z.string(),
          描述: z.string(),
          弱点: z.string(),
        })
        .prefault({
          名称: '待初始化',
          描述: '待初始化',
          弱点: '待初始化',
        }),
      背景经历及人物关系: z.string().prefault('待初始化'),
      穿着: z.string().prefault('待初始化'),
      性格: z
        .object({
          核心特质: z.string(),
          内在矛盾: z.string(),
          动机系统: z.object({
            公开: z.string(),
            真实: z.string(),
            不愿承认: z.string(),
          }),
          恐惧与欲望: z.object({
            最害怕: z.string(),
            最渴望: z.string(),
          }),
        })
        .prefault({
          核心特质: '待初始化',
          内在矛盾: '待初始化',
          动机系统: {
            公开: '待初始化',
            真实: '待初始化',
            不愿承认: '待初始化',
          },
          恐惧与欲望: {
            最害怕: '待初始化',
            最渴望: '待初始化',
          },
        }),
      动态状态: z.object({
        核心情绪: z.string().prefault('平静'),
        身体状态: z.string().prefault('健康'),
        堕落度: z.coerce
          .number()
          .int()
          .transform(value => _.clamp(value, 0, 100))
          .prefault(0),
        服从度: z.coerce
          .number()
          .int()
          .transform(value => _.clamp(value, 0, 100))
          .prefault(0),
        好感度: z.coerce
          .number()
          .int()
          .transform(value => _.clamp(value, 0, 100))
          .prefault(0),
        技能熟练度: z.coerce
          .number()
          .int()
          .transform(value => _.clamp(value, 0, 100))
          .prefault(0),
      }),
    }),
  ),
});

$(() => {
  registerMvuSchema(Schema);
});

